import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"产品定位与边界","description":"","frontmatter":{},"headers":[],"relativePath":"product/overview.md","filePath":"product/overview.md","lastUpdated":1780509827000}'),d={name:"product/overview.md"};function i(l,e,s,n,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="产品定位与边界" tabindex="-1">产品定位与边界 <a class="header-anchor" href="#产品定位与边界" aria-label="Permalink to &quot;产品定位与边界&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p>Codex-to-IM 是本机 bridge，不是云端托管服务。它把本机 Codex / Claude Code 会话接入飞书 IM 通道，让用户在聊天软件里继续操作本地 coding session。</p><h2 id="目标用户" tabindex="-1">目标用户 <a class="header-anchor" href="#目标用户" aria-label="Permalink to &quot;目标用户&quot;">​</a></h2><ul><li>远程操作型用户：离开本机 IDE 后，仍希望在飞书里继续某个会话。</li><li>团队协作型用户：希望把一个本地 coding session 接入群聊，团队成员能看到进度、检查结果、触发后续命令。</li><li>本地自动化用户：希望通过 IM 触发诊断、历史查看、shell、定时 prompt、文件回传等工作流，同时保持配置和日志仍在本机。</li></ul><h2 id="codex-to-im-负责什么" tabindex="-1">Codex-to-IM 负责什么 <a class="header-anchor" href="#codex-to-im-负责什么" aria-label="Permalink to &quot;Codex-to-IM 负责什么&quot;">​</a></h2><ul><li>接收 IM 消息，识别命令或普通 prompt。</li><li>把聊天绑定到本地 <code>BridgeSession</code>。</li><li>按会话配置选择 Codex 或 Claude Code 运行路径。</li><li>把流式输出、工具调用、权限请求、历史、附件和诊断结果发回 IM。</li><li>维护本地配置、通道实例、绑定、会话缓存和审计日志。</li></ul><h2 id="codex-to-im-不负责什么" tabindex="-1">Codex-to-IM 不负责什么 <a class="header-anchor" href="#codex-to-im-不负责什么" aria-label="Permalink to &quot;Codex-to-IM 不负责什么&quot;">​</a></h2><ul><li>不托管用户代码仓库。</li><li>不代替 Codex / Claude Code 管理账号登录态。</li><li>不改写 <code>~/.codex</code> 或 Claude Code 自有会话格式。</li><li>不把本地会话同步到远端数据库。</li></ul><h2 id="产品概念" tabindex="-1">产品概念 <a class="header-anchor" href="#产品概念" aria-label="Permalink to &quot;产品概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>用户视角</th><th>开发者视角</th></tr></thead><tbody><tr><td><code>BridgeSession</code></td><td>一条可持续的本地对话</td><td>Codex-to-IM 自有 session 容器</td></tr><tr><td><code>ChannelChat</code></td><td>某个飞书群聊或单聊当前接到哪条会话</td><td>IM chat 到 <code>BridgeSession.id</code> 的绑定</td></tr><tr><td><code>IMChannel</code></td><td>一个飞书机器人入口</td><td>adapter 实例和平台配置</td></tr><tr><td>Runtime</td><td>当前用 Codex 还是 Claude Code</td><td>provider 路由的第一层</td></tr><tr><td>Provider</td><td>用 SDK、pty 还是 tmux 运行</td><td>provider 路由的第二层</td></tr></tbody></table><p>详细业务模型见 <a href="./../architecture/current">当前架构</a>。</p><h2 id="设计模块" tabindex="-1">设计模块 <a class="header-anchor" href="#设计模块" aria-label="Permalink to &quot;设计模块&quot;">​</a></h2><ul><li>类型和通道地址：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/domain/index.ts" target="_blank" rel="noreferrer">src/domain/index.ts</a></li><li>通道抽象：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/contracts.ts" target="_blank" rel="noreferrer">src/channels/contracts.ts</a></li><li>会话绑定：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/session/channel-router.ts" target="_blank" rel="noreferrer">src/bridge/session/channel-router.ts</a></li><li>会话注册表：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/session/registry.ts" target="_blank" rel="noreferrer">src/bridge/session/registry.ts</a></li><li>本地存储：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a></li></ul>',14)])])}const m=t(d,[["render",i]]);export{b as __pageData,m as default};
